var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"첫 번째 정착자들은 세상에 큰 재앙이 닥칠 것을 예견했다.","JPN":"最初の定着者は世界に大きな災いが訪れることを予見したんじゃ。","ENG":"The First Settlers predicted that a great disaster would befall this world.","TWN":"第一批定居者預言世界將遭遇一場浩劫。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그래서 숲의 요정들이 속삭여 준 지식으로 낙원문이라는 커다란 탑을 세웠다고 하지.","JPN":"だから、森の妖精たちがささやいてくれた知識をもって楽園の門という大きな塔を建てたという。","ENG":"So they used the knowledge whispered by the forest fairies to erect the gigantic tower known as \\"Avalon's Gate\\".","TWN":"因此藉由森林精靈私語的知識，築起一座名為樂園門的巨塔。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"어떤 원리인지 우리 같은 무지렁이들은 알 수 없지만, 낙원문은 나라를 침식에서 지켜줬다네.","JPN":"わしらのような無学な者にはどんな原理かわからんが、楽園の門は国を侵食から守ってくれたそうじゃ。","ENG":"Although ordinary people like us don't know the principles behind it, Avalon's Gate saved this country from the Corruption.","TWN":"雖然像我們這種凡夫俗子，無法知道是什麼原理，但樂園門確實保護國家免於侵蝕之災。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"무서운 침식체들도 낙원문이 건재할 때는 맥을 못 췄지.","JPN":"恐ろしい侵食体も楽園の門が健在だった頃は力を発揮できなかった。","ENG":"Those nasty C.O.s didn't stand a chance when Avalon's Gate was standing tall.","TWN":"在樂園門還在時，連可怕的侵蝕體都無計可施。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 침식의 날이 시작된 지 얼마 지나지 않아 낙원문은 갑자기 가동을 멈췄어.","JPN":"じゃが、侵食の日が始まって間もない頃、楽園の門は急に稼働を停止したんじゃ。","ENG":"However, only a few days after the Day of Corruption, Avalon's Gate suddenly stopped working.","TWN":"不過在侵蝕之日開始後不久，樂園門突然停止運作。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"그러자 노르드나빅 전역에 침식 현상이 일어났고, 지옥이 펼쳐졌지.","JPN":"同時にノルドナビックの全域に侵食現象が起こり、地獄と化した。","ENG":"With the Counterside Effect sweeping across Nordnavik, all hell broke loose.","TWN":"於是在諾爾德萊比全區發生侵蝕現象，彷彿人間地獄一般。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"그 날의 전말을 되돌아볼 여력이 생겼을 즈음엔 이미 나라가 엉망진창이었어.","JPN":"あの日の顛末を振り返る余力ができた頃にはもう国はボロボロになっておった。","ENG":"By the time we were able to look back at this catastrophe, the country was already in shambles.","TWN":"當我有餘力去回想那天的始末時，國家已經是一團糟。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"성자들은 모두 침식체에게 맞서다 죽고, 임금께선 후계자를 결정하지도 못한 채 승하하셨지.","JPN":"聖者はみな侵食体に立ち向かって死に、王は後継者を決めることもできないまま崩御された。","ENG":"All Helgons had died fending off C.O.s, and the king passed away without declaring an heir to the throne.","TWN":"聖者們全都在對抗侵蝕體時死去，國王也在來不及决定繼承者的情况下便駕崩。"},"stage":{"bg":"AB_UI_NKM_UI_CUTSCEN_BG_FIRE","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"그리고 임금의 총애를 받던 총사대장 큐리안은…….","JPN":"そして王の寵愛を受けていた銃士隊長キュリアンは……","ENG":"And Curian, the king's most beloved soldier...","TWN":"而國王的心腹 隊長庫里安……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"낙원문의 중추인 열쇠를 가지고 어디론가 떠났다는 기록을 마지막으로 행방이 묘연해졌다네.","JPN":"楽園の門の要である鍵を持ってどこかへ向かったという記録を最後に、行方不明になったのじゃ。","ENG":"Records show that he took the Key from Avalon's Gate and disappeared.","TWN":"則是帶著樂園門的鑰匙下落不明。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"그래서 재건단은 파괴된 낙원문을 복원하려고 시도 중이야. 나라의 흥망을 가른 사건이니까.","JPN":"それで再建団は破壊された楽園の門の復元しようとしているんだ。国の興亡を決めた事件だからね。","ENG":"The Alliance is trying its best to rebuild Avalon's Gate since it was what determined the fate of this country.","TWN":"因此重建委員會正試圖復原遭破壞的樂園門，因爲此事攸關國家存亡。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"하지만 지식을 전수 받은 왕족이 없는 한, 그건 결국 모조품에 지나지 않아.","JPN":"でも知識を授けられた王族がいない限り、それは結局レプリカに過ぎない。","ENG":"But without the knowledge passed down to the Royal bloodline, it'll be nothing more than a replica of the original.","TWN":"但若沒有得知知識的皇族，那終究只是仿冒品而已。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"우리는 오랫동안 침식에 시달려 왔네. 침식은 우리의 모든 것을 앗아갔지.","JPN":"わしらは長らく侵食に苦しんできたんじゃ。侵食は全てを奪っていったからのう。","ENG":"We've suffered for too long from the C.O.s. The Corruption took everything away from us.","TWN":"我們長期為侵蝕所苦，侵蝕奪走我們的一切。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"살기 위해 고향을 떠나 여기까지 왔건만, 침식의 고통은 하루도 우릴 놓아 주지 않았어.","JPN":"生きるために故郷を離れてここまで来たのに、侵食の苦痛は一日もわしらを放っておいてくれなかった。","ENG":"I fled my hometown and came all the way here. But the suffering caused by the Corruption wouldn't let go for even just one day.","TWN":"爲了活下去，我們離開家鄉來到這裡，但侵蝕的痛苦卻沒有一天放過我們。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"그러던 어느날 우리 앞에 나타난 거라네.","JPN":"そんなある日、私たちの前に現われたのじゃ。","ENG":"Then one day, you appeared.","TWN":"然而某一天，在我們面前，"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ONIL_BORDER_NULL_NAMED","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ONIL_BORDER_NULL_NAMED","text":{"KOREA":"자신이 큐리안이라고 주장하는 젊은 친구가 말이야.","JPN":"自身をキュリアンだと主張する若者がな。","ENG":"A young fellow who went by the name \\"Curian\\".","TWN":"出現一個自稱是庫里安的年輕人。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"알고 있던 것과 다른 점이 있어? 아니면 다른 기억이 떠올랐다거나.","JPN":"知っていることと違うところはある？　それとも別の記憶を思い出したとか。","ENG":"Is there something you'd like to add? Or did you remember something?","TWN":"這和你認知的有什麼差異嗎？或是有想起什麼嗎？"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"나는……. 낙원문의 기능이 한계에 달했으니 열쇠를 운반해야 한다는 명령을 받았다.","JPN":"私は……楽園の門の機能が限界に達したから鍵を運べと命令された。","ENG":"I... was ordered to move the Key as Avalon's Gate reached its limit.","TWN":"我……我收到命令，説樂園門的功能已經達到極限，需要移動鑰匙。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};